import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Conway's Game of Life - Next Generation", () => {
  it.todo("should return empty for empty grid");
  it.todo("should kill a single live cell with no neighbors (underpopulation)");
  it.todo("should kill live cells with only one neighbor (underpopulation)");
  it.todo("should keep alive a live cell with 2 live neighbors (survival)");
  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
  it.todo("should bring a dead cell to life with exactly 3 live neighbors (reproduction)");
  it.todo("should keep a 2x2 block unchanged (still life)");
  it.todo("should oscillate a vertical blinker to horizontal (oscillator)");
  it.todo("should handle negative coordinates");
});
